"use strict";parserFactory.register("novelhi.com",()=>new NovelhiParser);class NovelhiParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=e.querySelector("div.bookChapter a.fr");return[...(await HttpClient.wrapFetch(t)).responseXML.querySelectorAll("div.dirList a")].map(t=>NovelhiParser.LinkToChapter(t,e.baseURI))}static LinkToChapter(e,t){let r=e.getAttribute("href")||e.href;return r&&!r.startsWith("http")&&(r=new URL(r,t).href),{sourceUrl:r,title:e.querySelector("span")?.textContent?.trim()||e.textContent.trim()}}findContent(e){return e.querySelector("#readcontent #showReading")}extractTitleImpl(e){return e.querySelector("div.tit h1")}findChapterTitle(e){return e.querySelector("#readcontent .book_title h1")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.bookCover")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.intro_txt")]}cleanInformationNode(e){return util.removeChildElementsMatchingSelector(e,"a"),e}}